    public static void main(String[] args) {
        int n = 4, W = 7;
        int[] wt = {1, 3, 4, 5};
        int[] val = {1, 4, 5, 7};
        Solution obj = new Solution();
        System.out.println(obj.knapSack(W, wt, val, n));
