// Class to solve 0/1 Knapsack using memoization
class Solution {
    // Function to compute maximum value
    knapSackUtil(ind, W, wt, val, dp) {
        // Base case: if only one item left
        if (ind === 0) {
            if (wt[0] <= W) return val[0];
            else return 0;
        }
        // If already computed return it
        if (dp[ind][W] !== -1) return dp[ind][W];

        // Exclude current item
        let notTaken = this.knapSackUtil(ind - 1, W, wt, val, dp);

        // Include current item if possible
        let taken = -Infinity;
        if (wt[ind] <= W) {
            taken = val[ind] + this.knapSackUtil(ind - 1, 
                                                 W - wt[ind], 
                                                 wt, val, dp);
        }

        // Store result in dp
        dp[ind][W] = Math.max(notTaken, taken);
        return dp[ind][W];
    }

    // Main function to call
    knapSack(W, wt, val, n) {
        let dp = Array.from({ length: n }, 
                            () => Array(W + 1).fill(-1));
        return this.knapSackUtil(n - 1, W, wt, val, dp);
    }
}

